untar se o cliente prefere reembolso ou troca, depois criar ticket com issue_type devolucao contendo número do pedido, problema descrito e resolução escolhida, depois enviar mensagem: Sua solicitação de devolução foi registrada. Nossa equipe de pedidos verificará e entrará em contato.","fallback_message":"Sua solicitação de devolução foi registrada. Nossa equipe de pedidos verificará e entrará em contato.","enable_intent_exits":true,"intent_financeiro":true,"intent_suporte":true}},{"id":"node_8_ticket_pedidos","type":"ai_response","position":{"x":550,"y":820},"data":{"label":"Ticket Pedidos + Transfer","persona_id":"8b5a5acb-49a0-4acd-81c0-b6249529ed1d","persona_name":"Helper Pedidos","max_interactions":2,"forbid_questions":false,"forbid_options":true,"response_goal":"Consultar pedido e criar ticket se não resolver.","context_prompt":"A IA deve consultar o pedido via check_tracking se possível. Se não resolver, criar ticket com issue_type pedido contendo número do pedido e problema, depois enviar mensagem: Sua solicitação sobre o pedido foi registrada. Nossa equipe de pedidos verificará e te informará.","fallback_message":"Sua solicitação sobre o pedido foi registrada. Nossa equipe de pedidos verificará e te informará.","enable_intent_exits":true,"intent_devolucao":true,"intent_suporte":true}},{"id":"node_9_transfer_suporte_sistema","type":"transfer","position":{"x":550,"y":1040},"data":{"label":"Transfer Suporte Sistema","message":"Vou te encaminhar para o suporte técnico. Um momento.","transfer_type":"department","department_id":"fd4fcc90-22e4-4127-ae23-9c9ecb6654b4","department_name":"Suporte Sistema"}},{"id":"node_10_transfer_comercial_nacional","type":"transfer","position":{"x":550,"y":1180},"data":{"label":"Transfer Comercial Nacional","message":"Vou te conectar com nosso time comercial. Um momento.","transfer_type":"department","department_id":"f446e202-bdc3-4bb3-aeda-8c0aa04ee53c","department_name":"Comercial - Nacional"}},{"id":"node_11_transfer_comercial_i